query:
-- Atacantes (ATA)
SELECT 'Atacantes' as filtro, COUNT(*) as total FROM players WHERE position IN ('ATA') OR altPositions LIKE '%ATA%';
-- Pontas (PD, PE)
SELECT 'Pontas' as filtro, COUNT(*) as total FROM players WHERE position IN ('PD', 'PE') OR altPositions LIKE '%PD%' OR altPositions LIKE '%PE%';
-- Meio-Campo (MC, VOL, MEI, MD, ME)
SELECT 'Meio-Campo' as filtro, COUNT(*) as total FROM players WHERE position IN ('MC', 'VOL', 'MEI', 'MD', 'ME') OR altPositions REGEXP '(^|,)(MC|VOL|MEI|MD|ME)(,|$)';
-- Laterais (LD, LE)
SELECT 'Laterais' as filtro, COUNT(*) as total FROM players WHERE position IN ('LD', 'LE') OR altPositions REGEXP '(^|,)(LD|LE)(,|$)';
-- Zagueiros (ZAG)
SELECT 'Zagueiros' as filtro, COUNT(*) as total FROM players WHERE position = 'ZAG' OR altPositions LIKE '%ZAG%';
-- Goleiros (GK)
SELECT 'Goleiros' as filtro, COUNT(*) as total FROM players WHERE position = 'GK';

